const input = $input.first().json;

const aiResponse = (input.ai_response || '').trim();
const pushName = input.pushName || 'cliente';
const businessName = input.businessName || 'nuestro equipo';

let response;
if (aiResponse && aiResponse.length > 10) {
  response = aiResponse + '

_Si deseas hablar con un agente, responde *AGENTE* y te transferimos de inmediato._';
} else {
  response = 'Hola ' + pushName + '! Recibimos tu mensaje y lo estamos revisando. Un especialista de ' + businessName + ' te contactará en breve.

Si es urgente, responde *AGENTE* para atención inmediata.';
}

return [{
  json: {
    response,
    intent: 'fallback',
    confidence: input.confidence || 0,
    escalated: false,
    original_intent: input.intent || 'unknown'
  }
}];
